import okhttp3.*
import java.io.IOException

class HttpApiClient {

    private val client = OkHttpClient()

    fun sendRequest(url: String, method: String, body: RequestBody? = null): String {
        val request = Request.Builder()
            .url(url)
            .method(method, body)
            .build()

        return try {
            client.newCall(request).execute().use { response ->
